body.script:
const q = (a) => document.getElementById(a);
const din = q('date');
const wordel = q('word');

function formatDate(date) {
  return new Date(date).toISOString().split('T')[0];
}

function seldate(d) {
  din.value = formatDate(d);
}

function offsetDate(offset) {
  const base = din.value ? new Date(din.value) : new Date();
  seldate(base.getTime() + offset);
}

q('seltoday').onclick = () => seldate(Date.now());
q('yest').onclick = () => offsetDate(-86400000);
q('tom').onclick = () => offsetDate(86400000);

async function fetchWordle(d) {
  try {
    const endpoint = `https://corsproxy.io/?url=https://www.nytimes.com/svc/wordle/v2/${d}.json`;
    const res = await fetch(endpoint);

    if (res.status === 429) throw new Error('Rate limit exceeded.');
    if (res.status === 404) throw new Error('Date not found.');
    if (!res.ok) throw new Error('Fetch failed.');

    const json = await res.json();
    return json.solution;
  } catch(e) {
    return e;
  }
}

q("sub").onclick = async function() {
  const d = din.value;
  if (!d) return alert('Enter a date.');

  const date = new Date(d);
  if (date.getTime() < 1624060800000) {
    return alert("Date must be after 2021-06-19");
  }

  const word = await fetchWordle(d);
  wordel.innerText = word instanceof Error
    ? 'Error: ' + word.message
    : word;
};
